import Vue from "vue";
import VueRouter from "vue-router";
import Home from "@/views/Home.vue";
import PokemonDetailsModal from "@/views/PokemonDetailsModal.vue";
import BaseLayout from "@/layouts/BaseLayout.vue";

Vue.use(VueRouter);

const routes = [
  {
    path: "/",
    component: BaseLayout,
    children: [
      {
        path: "/",
        name: "Home",
        component: Home,
        children: [
          {
            path: "/:id/details",
            name: "PokemonDetailsModal",
            component: PokemonDetailsModal,
          },
        ],
      },
      {
        path: "/about",
        name: "About",
        // route level code-splitting
        // this generates a separate chunk (about.[hash].js) for this route
        // which is lazy-loaded when the route is visited.
        component: () =>
          import(/* webpackChunkName: "about" */ "@/views/About.vue"),
      },
      {
        path: "/comparePokemons",
        name: "ComparePokemons",
        // route level code-splitting
        // this generates a separate chunk (about.[hash].js) for this route
        // which is lazy-loaded when the route is visited.
        component: () =>
          import(/* webpackChunkName: "comparePokemons" */ "@/views/ComparePokemons.vue"),
      },
      {
        path: "/settings",
        name: "Settings",
        // route level code-splitting
        // this generates a separate chunk (about.[hash].js) for this route
        // which is lazy-loaded when the route is visited.
        component: () =>
          import(/* webpackChunkName: "settings" */ "@/views/Settings.vue"),
      },
    ],
  },
];

const router = new VueRouter({
  mode: "history",
  base: process.env.BASE_URL,
  routes,
});

export default router;
