<template>
  <v-dialog
    v-model="dialog"
    max-width="500px"
    @keydown="closeDialog"
    @click:outside="closeDialog"
  >
    <v-card v-if="!isLoading">
      <v-img
        class="white--text align-end"
        contain
        :src="`https://pokeres.bastionbot.org/images/pokemon/${pokemon.id}.png`"
        :lazy-src="
          `https://pokeres.bastionbot.org/images/pokemon/${pokemon.id}.png`
        "
        :alt="pokemon.name"
        height="200px"
      >
        <template v-slot:placeholder>
          <v-row class="fill-height ma-0" align="center" justify="center">
            <v-progress-circular
              indeterminate
              color="secondary lighten-1"
            ></v-progress-circular>
          </v-row>
        </template>
      </v-img>
      <v-divider></v-divider>
      <v-card-title class="headline">
        Pokemon Details: {{ pokemon.name }}
      </v-card-title>
      <v-card-text>
        <v-simple-table>
          <template v-slot:default>
            <tbody>
              <tr>
                <th>Id</th>
                <td>{{ pokemon.id }}</td>
              </tr>
              <tr>
                <th>Weight</th>
                <td>{{ pokemon.weight }}</td>
              </tr>
              <tr>
                <th>Height</th>
                <td>{{ pokemon.height }}</td>
              </tr>
              <tr>
                <th>Types</th>
                <td>
                  <v-chip-group column>
                    <v-chip
                      class="my-2 mx-1 white--text"
                      v-for="item in pokemon.types"
                      :key="`type-${item.id}`"
                      :color="getTypeColor(item.id)"
                    >
                      {{ item.name }}
                    </v-chip>
                  </v-chip-group>
                </td>
              </tr>
              <tr>
                <th>Abilities</th>
                <td>
                  <v-chip-group column>
                    <v-chip
                      class="my-2 mx-1 white--text"
                      v-for="item in pokemon.abilities"
                      :key="`type-${item.id}`"
                      :color="`success`"
                      outlined
                    >
                      {{ item.name }}
                      <v-icon right>
                        mdi-eye{{ item.isHidden ? "-off" : "" }}-outline
                      </v-icon>
                    </v-chip>
                  </v-chip-group>
                </td>
              </tr>
            </tbody>
          </template>
        </v-simple-table>

        <template v-if="hasStats">
          <br />
          <h3 class="title text-center">Stats</h3>
          <v-divider></v-divider>
          <radar-chart
            :chart-data="chartData"
            :options="chartOptions"
          ></radar-chart>
        </template>
      </v-card-text>

      <v-card-actions>
        <v-spacer></v-spacer>
        <v-btn color="secondary darken-1" text @click="closeDialog">
          Close
        </v-btn>
        <v-btn
          color="primary darken-1"
          text
          @click="updateComparePokemons(pokemon)"
        >
          {{
            isPokemonInCompareList(pokemon.id)
              ? "Remove From Compare"
              : "Add To Compare"
          }}
        </v-btn>
      </v-card-actions>
    </v-card>
  </v-dialog>
</template>

<script>
import RadarChart from "@/components/RadarChart.vue";
import { mapState, mapGetters, mapActions } from "vuex";
import axios from "axios";

export default {
  components: {
    RadarChart,
  },
  computed: {
    hasStats() {
      return this.chartData.labels.length > 0;
    },
    ...mapState(["isDark"]),
    ...mapGetters([
      "getChartFontColor",
      "getChartAngleLinesColor",
      "getChartGridLinesColor",
      "isPokemonInCompareList",
    ]),
  },
  data() {
    return {
      dialog: true,
      isLoading: true,
      pokemon: null,
      chartData: {
        labels: [],
        datasets: [
          {
            label: "",
            backgroundColor: `${
              this.$vuetify.theme.themes[this.isDark ? "dark" : "light"]
                .secondary
            }7F`,
            data: [],
          },
        ],
      },
      chartOptions: {
        responsive: true,
        maintainAspectRatio: false,
        scale: {
          ticks: {
            beginAtZero: true,
            showLabelBackdrop: false,
          },
          pointLabels: {},
          gridLines: {},
          angleLines: {},
        },
      },
    };
  },

  mounted() {
    this.getPokemon();
    this.chartOptions.scale.ticks.fontColor = this.getChartFontColor;
    this.chartOptions.scale.pointLabels.fontColor = this.getChartFontColor;
    this.chartOptions.scale.angleLines.color = this.getChartAngleLinesColor;
    this.chartOptions.scale.gridLines.color = this.getChartGridLinesColor;
  },

  methods: {
    closeDialog(event) {
      this.dialog = false;
      this.$emit("close-dialog", event);
    },
    getPokemon() {
      console.log();
      this.isLoading = true;
      return axios
        .get(`https://pokeapi.co/api/v2/pokemon/${this.$route.params.id}`)
        .then((response) => {
          const { data } = response;
          console.log(data);
          const types = data.types.map((item) => {
            const { url, name } = item.type;
            var id = parseInt(url.match(/type\/\d+/)[0].substring(5));
            return { id, name, url, slot: item.slot };
          });
          const abilities = data.abilities.map((item) => {
            const { url, name } = item.ability;
            var id = parseInt(url.match(/ability\/\d+/)[0].substring(8));
            return { id, name, url, slot: item.slot, isHidden: item.is_hidden };
          });
          const stats = data.stats.map((item) => {
            const { url, name } = item.stat;
            var id = parseInt(url.match(/stat\/\d+/)[0].substring(5));
            return {
              id,
              name,
              url,
              effort: item.effort,
              baseStat: item.base_stat,
            };
          });
          this.pokemon = { ...data, types, abilities, stats };
          for (var i = 0; i < stats.length; i++) {
            this.chartData.labels[i] = stats[i].name;
            this.chartData.datasets[0].data[i] = stats[i].baseStat;
            this.chartData.datasets[0].label = this.pokemon.name;
          }
          this.isLoading = false;
        });
    },
    getTypeColor(id) {
      switch (id) {
        case 1:
          return "#aaaa99";
        case 2:
          return "#bb5544";
        case 3:
          return "#8899ff";
        case 4:
          return "#aa5599";
        case 5:
          return "#ddbb55";
        case 6:
          return "#bbaa66";
        case 7:
          return "#aabb22";
        case 8:
          return "#6666bb";
        case 9:
          return "#aaaabb";
        case 10:
          return "#ff4422";
        case 11:
          return "#3399ff";
        case 12:
          return "#77cc55";
        case 13:
          return "#ffcc33";
        case 14:
          return "#ff5599";
        case 15:
          return "#66ccff";
        case 16:
          return "#7766ee";
        case 17:
          return "#775544";
        case 18:
          return "#ee99ee";
        case 10001:
        case 10002:
        default:
          return "#aaaa99";
      }
    },
    ...mapActions(["updateComparePokemons"]),
  },
};
</script>

