import Vue from "vue";
import Vuex from "vuex";
import vuetify from "@/plugins/vuetify";

Vue.use(Vuex);

export default new Vuex.Store({
  state: {
    isDark: localStorage.getItem("isDark") == "true",
    isMiniNav: localStorage.getItem("isMiniNav") == "true",
    isExpandOnHover: localStorage.getItem("isExpandOnHover") == "true",
    comparePokemons:
      localStorage.getItem("comparePokemons") == null
        ? []
        : JSON.parse(localStorage.getItem("comparePokemons")),
  },
  getters: {
    getChartFontColor(state) {
      return state.isDark ? "#FFFFFF" : "#666666";
    },
    getChartAngleLinesColor(state) {
      return state.isDark ? "rgba(255,255,255,0.2)" : "rgba(0,0,0,0.2)";
    },
    getChartGridLinesColor(state) {
      return state.isDark ? "rgba(255,255,255,0.1)" : "rgba(0,0,0,0.1)";
    },
    isPokemonInCompareList: (state) => (id) => {
      return state.comparePokemons.some((item) => item.id === id);
    },
  },
  mutations: {
    updateIsDark(state, value) {
      state.isDark = value;
      localStorage.setItem("isDark", state.isDark);
      console.log(vuetify);
      vuetify.framework.theme.dark = value;
    },
    updateIsMiniNav(state, value) {
      if (value === false) {
        state.isExpandOnHover = value;
        localStorage.setItem("isExpandOnHover", state.isExpandOnHover);
      }
      state.isMiniNav = value;
      localStorage.setItem("isMiniNav", state.isMiniNav);
    },
    updateIsExpandOnHover(state, value) {
      if (value === true) {
        state.isMiniNav = value;
        localStorage.setItem("isMiniNav", state.isMiniNav);
      }
      state.isExpandOnHover = value;
      localStorage.setItem("isExpandOnHover", state.isExpandOnHover);
    },
    addToComparePokemons(state, value) {
      state.comparePokemons.push(value);
      localStorage.setItem(
        "comparePokemons",
        JSON.stringify(state.comparePokemons)
      );
    },
    removeFromComparePokemons(state, value) {
      state.comparePokemons = state.comparePokemons.filter(
        (item) => item.id != value.id
      );
      localStorage.setItem(
        "comparePokemons",
        JSON.stringify(state.comparePokemons)
      );
    },
  },
  actions: {
    updateComparePokemons({ commit, getters }, value) {
      if (getters.isPokemonInCompareList(value.id)) {
        commit("removeFromComparePokemons", value);
      } else {
        commit("addToComparePokemons", value);
      }
    },
  },
  modules: {},
});
