<template>
  <v-app id="inspire">
    <v-navigation-drawer
      v-model="drawer"
      app
      clipped
      :expand-on-hover="isExpandOnHover"
      :mini-variant="isMiniNav"
    >
      <v-list dense>
        <v-list-item link to="/">
          <v-list-item-action>
            <v-icon>mdi-home</v-icon>
          </v-list-item-action>
          <v-list-item-content>
            <v-list-item-title>Home</v-list-item-title>
          </v-list-item-content>
        </v-list-item>

        <v-list-item link to="/comparePokemons">
          <v-list-item-action>
            <v-icon>mdi-compare</v-icon>
          </v-list-item-action>
          <v-list-item-content>
            <v-list-item-title>Compare Pokemons</v-list-item-title>
          </v-list-item-content>
        </v-list-item>

        <v-list-item link to="/about">
          <v-list-item-action>
            <v-icon>mdi-contacts</v-icon>
          </v-list-item-action>
          <v-list-item-content>
            <v-list-item-title>About</v-list-item-title>
          </v-list-item-content>
        </v-list-item>
      </v-list>

      <template v-slot:append>
        <v-divider></v-divider>

        <v-list dense>
          <v-list-item link to="/settings">
            <v-list-item-action>
              <v-icon>mdi-settings</v-icon>
            </v-list-item-action>
            <v-list-item-content>
              <v-list-item-title>Settings</v-list-item-title>
            </v-list-item-content>
          </v-list-item>
        </v-list>
      </template>
    </v-navigation-drawer>

    <v-app-bar
      app
      color="primary"
      dark
      clipped-left
      :collapse-on-scroll="checkCollapseOnScroll"
    >
      <v-app-bar-nav-icon @click.stop="drawer = !drawer"></v-app-bar-nav-icon>
      <v-toolbar-title>
        Application
      </v-toolbar-title>
      <v-spacer></v-spacer>

      <v-menu bottom offset-y>
        <template v-slot:activator="{ on }">
          <v-btn icon v-on="on">
            <v-icon>mdi-apps</v-icon>
          </v-btn>
        </template>
        <v-list>
          <v-list-item>
            <v-switch
              v-model="isDark"
              inset
              :label="isDarkThemeLabel"
            ></v-switch>
          </v-list-item>
          <v-list-item link>
            <v-icon class="mr-3">mdi-crop-free</v-icon>
            <v-list-item-content>
              <v-list-item-title>Option 1</v-list-item-title>
            </v-list-item-content>
          </v-list-item>
          <v-list-item link>
            <v-icon class="mr-3">mdi-home</v-icon>
            <v-list-item-content>
              <v-list-item-title>Option 2</v-list-item-title>
            </v-list-item-content>
          </v-list-item>
        </v-list>

        <v-divider></v-divider>

        <v-list>
          <v-list-item link to="/settings">
            <v-icon class="mr-3">mdi-settings</v-icon>
            <v-list-item-content>
              <v-list-item-title>Settings</v-list-item-title>
            </v-list-item-content>
          </v-list-item>
        </v-list>
      </v-menu>
    </v-app-bar>

    <v-content>
      <v-container fluid>
        <router-view></router-view>
      </v-container>
    </v-content>
    <v-footer app inset absolute>
      <span>&copy; 2019</span>
    </v-footer>
  </v-app>
</template>

<script>
import { mapState } from "vuex";

export default {
  computed: {
    isDarkThemeLabel() {
      return this.isDark ? "Dark" : "Light";
    },
    checkCollapseOnScroll() {
      return this.isMiniNav && !this.isExpandOnHover;
    },
    isDark: {
      get() {
        return this.$store.state.isDark;
      },
      set(value) {
        this.$store.commit("updateIsDark", value);
      },
    },
    ...mapState(["isMiniNav", "isExpandOnHover"]),
  },

  data: () => ({
    drawer: null,
  }),
};
</script>
